#include <stdio.h>
#include <string.h>
#define MAXN 100005
#define MAXK 1000000000
int N, K;
char S[MAXN];
int dp[MAXN][MAXN];
void generateLuckyStrings(char *str, int len, int idx) {
    if (idx == len) {
        // Check if the generated string is a CNS
        int replacements = 0;
        for (int i = 0; i < N; i++) {
            int j = 0;
            for (int k = 0; k < len; k++) {
                while (j < strlen(S) && S[j] != str[k]) j++;
                if (j == strlen(S)) {
                    replacements += len - k;
                    break;
                }
                j++;
            }
        }
        if (replacements <= K) {
            printf("%s\n", str);
        }
    } else {
        str[idx] = '4';
        generateLuckyStrings(str, len, idx + 1);
        str[idx] = '7';
        generateLuckyStrings(str, len, idx + 1);
    }
}
int main() {
    scanf("%d %d", &N, &K);
    for (int i = 0; i < N; i++) {
        scanf("%s", S);
    }
    for (int len = 1; len <= MAXN; len++) {
        char str[len + 1];
        str[len] = '\0';
        generateLuckyStrings(str, len, 0);
    }
    return 0;
}

