import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int K = sc.nextInt();
        String[] S = new String[N];
        for (int i = 0; i < N; i++) {
            S[i] = sc.next();
        }
        for (int len = 1; len <= 100005; len++) {
            generateLuckyStrings("", len, S, K);
        }
    }
    public static void generateLuckyStrings(String str, int len, String[] S, int K) {
        if (str.length() == len) {
            // Check if the generated string is a CNS
            int replacements = 0;
            for (int i = 0; i < S.length; i++) {
                int j = 0;
                for (int k = 0; k < len; k++) {
                    while (j < S[i].length() && S[i].charAt(j) != str.charAt(k)) j++;
                    if (j == S[i].length()) {
                        replacements += len - k;
                        break;
                    }
                    j++;
                }
            }
            if (replacements <= K) {
                System.out.println(str);
            }
        } else {
            generateLuckyStrings(str + "4", len, S, K);
            generateLuckyStrings(str + "7", len, S, K);
        }
    }
}

